require_once __DIR__ . '/../config/database.php'; require_once __DIR__ . '/../includes/functions.php'; require_admin();
if(isset($_GET['delete'])){$stmt=$pdo->prepare('DELETE FROM news WHERE id=?');$stmt->execute([(int)$_GET['delete']]);redirect('admin/news.php');}
$id=(int)($_GET['edit']??0);$edit=['title'=>'','content'=>'','image'=>'']; if($id){$stmt=$pdo->prepare('SELECT * FROM news WHERE id=?');$stmt->execute([$id]);$edit=$stmt->fetch() ?: $edit;}
if($_SERVER['REQUEST_METHOD']==='POST'){$image=upload_image('image') ?: ($edit['image']??null); if(!empty($_POST['id'])){$stmt=$pdo->prepare('UPDATE news SET title=?, content=?, image=? WHERE id=?');$stmt->execute([$_POST['title'],$_POST['content'],$image,$_POST['id']]);}else{$stmt=$pdo->prepare('INSERT INTO news (title,slug,content,image,author_id) VALUES (?,?,?,?,?)');$stmt->execute([$_POST['title'],slugify($_POST['title']).'-'.time(),$_POST['content'],$image,current_user()['id']]);}redirect('admin/news.php');}
$news=$pdo->query('SELECT * FROM news ORDER BY created_at DESC')->fetchAll();$title='Kelola Berita';require_once __DIR__ . '/_layout.php';
?>
<div class="grid grid-2"><form class="card card-body" method="post" enctype="multipart/form-data"><h2><?= $id?'Edit':'Tambah' ?> Berita</h2><input type="hidden" name="id" value="<?= e($id) ?>"><div class="form-row"><label class="label">Judul</label><input class="input" name="title" value="<?= e($edit['title']) ?>" required></div><div class="form-row"><label class="label">Konten</label><textarea name="content" rows="6" required><?= e($edit['content']) ?></textarea></div><div class="form-row"><label class="label">Gambar</label><input class="input" type="file" name="image" accept="image/*"></div><button class="btn btn-primary">Simpan</button></form><div class="table-wrap"><table><thead><tr><th>Judul</th><th>Aksi</th></tr></thead><tbody><?php foreach($news as $n): ?><tr><td><?= e($n['title']) ?></td><td><a href="?edit=<?= $n['id'] ?>">Edit</a> | <a onclick="return confirm('Hapus?')" href="?delete=<?= $n['id'] ?>">Hapus</a></td></tr><?php endforeach; ?></tbody></table></div></div>
